}

Here are the public test cases for feature8_torrent_count_metric:
{
  "description": "Create a gauge metric that reports the number of torrents for a specific state and category, preserving both values as labels along with the monitored server label.",
  "cases": [
    {
      "input": {
        "operation": "torrent_count_metric",
        "state": "downloading",
        "category": "movies",
        "count": 10,
        "config": {
          "metrics_prefix": "qbittorrent"
        }
      },
      "expected_output": "metric_name=qbittorrent_torrents_count\nmetric_type=gauge\nvalue=10\nlabels={\"category\":\"movies\",\"server\":\"localhost:8080/qbt/\",\"status\":\"downloading\"}\nhelp=Number of torrents in status downloading under category movies\n"
    }
  ]
}
